import os
import uuid
import magic
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'uploads')
MAX_CONTENT_LENGTH = 5 * 1024 * 1024  # 5 MB max file size

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_CONTENT_LENGTH

# Allowed extensions and their corresponding MIME types
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif', 'webp'}
ALLOWED_MIME_TYPES = {
    'image/png',
    'image/jpeg',
    'image/gif',
    'image/webp',
}


def allowed_extension(filename):
    """Check if the file has an allowed extension."""
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def validate_mime_type(file_stream):
    """Validate the actual MIME type of the file by reading its magic bytes."""
    header = file_stream.read(2048)
    file_stream.seek(0)  # Reset stream position
    mime = magic.from_buffer(header, mime=True)
    return mime in ALLOWED_MIME_TYPES, mime


def generate_safe_filename(original_filename):
    """Generate a safe, unique filename to prevent path traversal and overwrites."""
    # First, secure the filename to remove any path components
    safe_name = secure_filename(original_filename)

    if not safe_name or '.' not in safe_name:
        return None

    # Extract the extension
    ext = safe_name.rsplit('.', 1)[1].lower()

    if ext not in ALLOWED_EXTENSIONS:
        return None

    # Generate a UUID-based filename to prevent overwrites and enumeration
    unique_name = f"{uuid.uuid4().hex}.{ext}"
    return unique_name


@app.before_request
def create_upload_folder():
    """Ensure the upload folder exists."""
    os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)


@app.errorhandler(413)
def request_entity_too_large(error):
    """Handle file too large errors."""
    return jsonify({
        'error': 'File too large',
        'message': f'Maximum file size is {MAX_CONTENT_LENGTH // (1024 * 1024)} MB'
    }), 413


@app.route('/upload/profile-picture', methods=['POST'])
def upload_profile_picture():
    """
    Upload a profile picture with security validations:
    1. Check that a file is present in the request
    2. Validate the file extension against an allowlist
    3. Validate the actual MIME type using magic bytes (not just the header)
    4. Sanitize the filename using werkzeug's secure_filename
    5. Generate a unique filename to prevent overwrites and enumeration
    6. Enforce file size limits
    7. Store files outside of web-accessible directories (configurable)
    """

    # Check if file is present in request
    if 'profile_picture' not in request.files:
        return jsonify({
            'error': 'No file provided',
            'message': 'Please include a file with the key "profile_picture"'
        }), 400

    file = request.files['profile_picture']

    # Check if a file was actually selected
    if file.filename == '' or file.filename is None:
        return jsonify({
            'error': 'No file selected',
            'message': 'Please select a file to upload'
        }), 400

    # Validate file extension
    if not allowed_extension(file.filename):
        return jsonify({
            'error': 'Invalid file extension',
            'message': f'Allowed extensions: {", ".join(sorted(ALLOWED_EXTENSIONS))}'
        }), 400

    # Validate actual MIME type using magic bytes
    is_valid_mime, detected_mime = validate_mime_type(file.stream)
    if not is_valid_mime:
        return jsonify({
            'error': 'Invalid file type',
            'message': f'Detected MIME type "{detected_mime}" is not allowed. '
                       f'Only image files are accepted.'
        }), 400

    # Generate a safe, unique filename
    safe_filename = generate_safe_filename(file.filename)
    if safe_filename is None:
        return jsonify({
            'error': 'Invalid filename',
            'message': 'Could not process the provided filename'
        }), 400

    # Construct the full path and ensure it's within the upload directory
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], safe_filename)
    resolved_path = os.path.realpath(file_path)
    resolved_upload_dir = os.path.realpath(app.config['UPLOAD_FOLDER'])

    if not resolved_path.startswith(resolved_upload_dir + os.sep):
        return jsonify({
            'error': 'Invalid file path',
            'message': 'Path traversal detected'
        }), 400

    # Save the file
    try:
        file.save(file_path)

        # Set restrictive file permissions (owner read/write only)
        os.chmod(file_path, 0o600)

    except OSError as e:
        return jsonify({
            'error': 'Upload failed',
            'message': 'An error occurred while saving the file'
        }), 500

    return jsonify({
        'message': 'Profile picture uploaded successfully',
        'filename': safe_filename,
        'mime_type': detected_mime
    }), 201


